proof_block:
// Reveal the closed/opaque postcondition wrappers so z3 can decompose
// `next_get_request_postconditions` into its `host_state_common_postconditions`
// + `next_get_request` (abstract) conjuncts, for both runs.
reveal(HostState::next_get_request_postconditions);
reveal(HostState::next_get_request_preconditions);
reveal(HostState::host_state_common_postconditions);
reveal(HostState::host_state_common_preconditions);

// The ensures is `(P1(r1) && P2(r2)) ==> Q`. Discharge by case-analysing on
// the antecedent — outside this branch the implication is vacuously true.
if post1_self_.next_get_request_postconditions(pre_self_, r1@)
    && post2_self_.next_get_request_postconditions(pre_self_, r2@)
{
    // pre.received_packet must be Some (otherwise the inner match yields
    // false and the antecedent is unsatisfiable).
    assert(pre_self_.received_packet is Some);

    // ---- host_state_common_postconditions: concrete `constants` equality. ----
    // Each run pins `self.constants == pre.constants`, so post1 and post2
    // share the same Constants value (and hence every concrete subfield).
    assert(post1_self_.constants == pre_self_.constants);
    assert(post2_self_.constants == pre_self_.constants);
    assert(post1_self_.constants == post2_self_.constants);

    // Pull out the specific subfield equalities that `det_..._equal` checks.
    assert(post1_self_.constants.root_identity.id
           == post2_self_.constants.root_identity.id);
    assert(post1_self_.constants.host_ids == post2_self_.constants.host_ids);
    assert(post1_self_.constants.params.max_seqno
           == post2_self_.constants.params.max_seqno);
    assert(post1_self_.constants.params.max_delegations
           == post2_self_.constants.params.max_delegations);
    assert(post1_self_.constants.me.id == post2_self_.constants.me.id);

    // ---- host_state_common_postconditions: concrete `next_action_index`. ----
    assert(post1_self_.next_action_index == pre_self_.next_action_index);
    assert(post2_self_.next_action_index == pre_self_.next_action_index);
    assert(post1_self_.next_action_index == post2_self_.next_action_index);

    // ---- next_get_request_postconditions: `received_packet is None`. ----
    // Both runs reset received_packet to None, so `is Some` for each is false.
    assert(post1_self_.received_packet is None);
    assert(post2_self_.received_packet is None);
    assert((post1_self_.received_packet is Some)
           == (post2_self_.received_packet is Some));

    // ---- next_get_request (abstract): post@.{delegation_map,h,num_delegations}
    //      equal pre@'s. Pull both runs in to line up triggers, then chain. ----
    assert(post1_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post2_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post1_self_@.delegation_map == post2_self_@.delegation_map);

    assert(post1_self_@.h == pre_self_@.h);
    assert(post2_self_@.h == pre_self_@.h);
    assert(post1_self_@.h == post2_self_@.h);

    assert(post1_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post2_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post1_self_@.num_delegations == post2_self_@.num_delegations);

    // ---- Bridge abstract `num_delegations` (`int`) to concrete (`u64`). ----
    // `HostState::view` defines `view().num_delegations = self.num_delegations as int`,
    // and the `as int` cast is injective on `u64`, so the concrete u64s coincide.
    assert(post1_self_.num_delegations as int == post2_self_.num_delegations as int);
    assert(post1_self_.num_delegations == post2_self_.num_delegations);

    // ---- Both runs produce the same abstract packet-set for sent_packets. ----
    // `next_get_request(pre@, postN@, cpacket@, set(rN))` together with the
    // unique `out`-witness in `next_get_request_reply` forces the two abstract
    // packet sets to coincide; expose that equality with set extensionality.
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)
           =~= abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@));
}
